import { TEST_IDS } from '../../../fixtures/test-ids.js'
import { ROUTES } from '../../../fixtures/routes.js'
import { RUNNING_ENDPOINTS } from '../../../fixtures/endpoints.js'

const IDS = TEST_IDS.running_ai
const PAGE_URL = ROUTES.running_ai_coach
const INJURY_COACH_EP = RUNNING_ENDPOINTS.INJURY_COACH

// ---------------------------------------------------------------------------
// Shared stub — onboarding check (middleware calls rt_users)
// ---------------------------------------------------------------------------
function stubRtUsers() {
  cy.intercept('GET', '**/rest/v1/rt_users*', {
    statusCode: 200,
    body: [{ id: 'test-user-id', onboarding_complete: true }],
  }).as('rtUsersCheck')
}

// ---------------------------------------------------------------------------
// 1. Disclaimer strip visible before any role is selected
// ---------------------------------------------------------------------------

describe('Injury AI Coach — Disclaimer strip', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
  })

  it('disclaimer strip is visible before selecting a role', () => {
    cy.get(`#${IDS.injury_disclaimer}`).should('be.visible')
  })
})

