// ---------------------------------------------------------------------------
// 4. Phase pills — select Acute, deselect on second click
// ---------------------------------------------------------------------------

describe('Injury AI Coach — Phase pills', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
    // Open the form by selecting Physio role
    cy.get(`#${IDS.injury_physio_card}`).click()
    cy.get(`#${IDS.injury_phase_acute}`).scrollIntoView()
  })

  it('clicking Acute pill marks it active', () => {
    cy.get(`#${IDS.injury_phase_acute}`).click()
    // Active pill should carry an aria-pressed="true" or a visual active class
    cy.get(`#${IDS.injury_phase_acute}`).should('have.attr', 'aria-pressed', 'true')
  })

  it('clicking active Acute pill again deselects it', () => {
    cy.get(`#${IDS.injury_phase_acute}`).click() // select
    cy.get(`#${IDS.injury_phase_acute}`).click() // deselect
    cy.get(`#${IDS.injury_phase_acute}`).should('have.attr', 'aria-pressed', 'false')
  })
})

// ---------------------------------------------------------------------------
// 5. Submit button disabled/enabled based on question length
// ---------------------------------------------------------------------------

describe('Injury AI Coach — Submit button validation', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
    cy.get(`#${IDS.injury_physio_card}`).click()
    cy.get(`#${IDS.injury_submit_btn}`).scrollIntoView()
  })

  it('submit button is disabled when question is fewer than 10 characters', () => {
    cy.get(`#${IDS.injury_question_input}`).clear().type('Short')
    cy.get(`#${IDS.injury_submit_btn}`).should('be.disabled')
  })

  it('submit button is enabled when question is 10 or more characters', () => {
    cy.get(`#${IDS.injury_question_input}`).clear().type('My knee hurts after running')
    cy.get(`#${IDS.injury_submit_btn}`).should('not.be.disabled')
  })
})

// ---------------------------------------------------------------------------
// 6. Emergency block — typing "10/10" pain replaces submit with red message
// ---------------------------------------------------------------------------

describe('Injury AI Coach — Emergency block', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
    cy.get(`#${IDS.injury_physio_card}`).click()
  })

  it('typing "10/10" triggers emergency message and hides submit button', () => {
    // Intercept injury_coach to assert it is NOT called
    cy.intercept('POST', `${INJURY_COACH_EP}**`, cy.spy().as('injuryCoachSpy'))

    cy.get(`#${IDS.injury_question_input}`)
      .clear()
      .type('I have 10/10 pain and cannot move my leg at all')

    // Submit button must disappear and an emergency message must be visible
    cy.get(`#${IDS.injury_submit_btn}`).should('not.exist')
    // scrollIntoView needed — emergency message may be inside overflow:hidden container
    cy.contains(/emergency|seek immediate|go to hospital|911|call/i)
      .scrollIntoView()
      .should('be.visible')

    // The POST must not have been called
    cy.get('@injuryCoachSpy').should('not.have.been.called')
  })
})

// ---------------------------------------------------------------------------
// 7. Successful submission — output card visible
// ---------------------------------------------------------------------------

describe('Injury AI Coach — Successful submission', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
    cy.get(`#${IDS.injury_physio_card}`).click()
  })

  it('successful POST → output card becomes visible', () => {
    cy.intercept('POST', `${INJURY_COACH_EP}**`, {
      statusCode: 200,
      body: {
        data: {
          content: '## Safe Activities\nRest.',
          role: 'physio',
          created_at: '2026-06-06T00:00:00Z',
        },
        escalate: false,
        message: 'OK',
      },
    }).as('postInjuryCoach')

    cy.get(`#${IDS.injury_body_part_input}`).clear().type('Left knee')
    cy.get(`#${IDS.injury_question_input}`)
      .clear()
      .type('What exercises can I do while recovering from a knee injury?')

    cy.get(`#${IDS.injury_submit_btn}`).click()
    cy.wait('@postInjuryCoach')

    cy.get(`#${IDS.injury_output_card}`).should('be.visible')
    cy.get(`#${IDS.injury_output_card}`).within(() => {
      cy.contains('Safe Activities').should('exist')
    })
  })
})

