// ---------------------------------------------------------------------------
// 9. API error — 500 shows error state
// ---------------------------------------------------------------------------

describe('Injury AI Coach — API error handling', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
    cy.get(`#${IDS.injury_physio_card}`).click()
  })

  it('500 response from injury-coach → error state shown to user', () => {
    cy.intercept('POST', `${INJURY_COACH_EP}**`, {
      statusCode: 500,
      body: { error: 'Internal server error' },
    }).as('postInjuryCoachError')

    cy.get(`#${IDS.injury_body_part_input}`).clear().type('Lower back')
    cy.get(`#${IDS.injury_question_input}`)
      .clear()
      .type('I have been having lower back pain for two weeks now')

    cy.get(`#${IDS.injury_submit_btn}`).click()
    cy.wait('@postInjuryCoachError')

    // Output card must NOT appear; an error indicator must be visible
    cy.get(`#${IDS.injury_output_card}`).should('not.exist')
    cy.contains(/error|failed|something went wrong/i).should('be.visible')
  })
})
